mapper.select:
SELECT di.id AS delivery_info_id, di.code, di.year, di.month, di.day, di.total_amount, di.created_at, di.updated_at, di.delivery_company_name, di.vehicle_number, di.tracking_number, di.supplier_id, di.purchase_order_id, dd.id AS detail_id, dd.quantity AS detail_quantity, dd.total_amount AS detail_total_amount, dd.product_id, dd.delivery_info_id AS delivery_info_id FROM delivery_info di LEFT JOIN delivery_detail dd ON di.id = dd.delivery_info_id
di.supplier_id = #{supplierId}
AND di.year = #{year}
AND di.month = #{month}
AND di.day = #{day}
ORDER BY di.created_at DESC, di.id, dd.id
